var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女と共にいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"걱정 마시죠. 이런 자리라면 비슷한 경험을 해봤으니까요.","JPN":"ご心配いりません。このようなことなら、以前経験したことがありますので。","ENG":"Don't worry. I've been in situations like this before.","TWN":"別擔心，這種場合，我有過類似的經驗。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"관련된 절차는 모두 숙지하고 있습니다. 달리 설명을 들을 필요는 없으니 시작하시죠.","JPN":"関連手続きはすべて熟知しています。別に説明を聞く必要はありませんので、始めてください。","ENG":"I'm fully familiar with the necessary procedures. So we can skip the explanations and get started.","TWN":"所有相關的流程我都已熟知，無需再多作說明，我們開始吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"……예의 차릴 필요 없이 예전처럼 대해도 좋다고요?","JPN":"……堅苦しいのはいいから、昔のように接してくれてもいい、と？","ENG":"...You say I can speak casually, like before?","TWN":"……可以不必拘泥禮節，像以前那樣對話嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"아닙니다. 기사단을 대표하는 자가 관리자님께 무례한 모습을 보일 순 없죠.","JPN":"いいえ。騎士団の代表たるもの、管理者に無礼な姿をお見せすることはできません。","ENG":"I'm afraid I can't do that. As the Captain of the Order, it would be improper of me to speak informally you, Administrator.","TWN":"不行。身為騎士團代表，怎麼能讓人看到我對管理者失禮呢？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"기사단장인 제가 허물없이 대했다간 관리자님도 곤란한 일을 겪으실 겁니다.","JPN":"騎士団長である私が気を許していたら、管理者もお困りになるはずでしょう。","ENG":"If I, as the Captain, were to act without formality, it might even cause you some trouble.","TWN":"若我以團長之姿輕率行事，反倒會讓管理者為難的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"조디악 나이츠의 단장이 아닌 한 명의 기사와 계약하고 싶다. 라…….","JPN":"ゾディアックナイツの団長ではなく、1人の騎士と契約したい、ですか……","ENG":"You want to make a contract not with the Captain of the Zodiac Knights, but with me, as an individual knight...","TWN":"你不是要和十二宮騎士團的團長簽訂契約，而是要和一名騎士……嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"역시 이상하신 분이네요. 대부분의 사람들은 제게 단장으로서의 소임을 요구했습니다.","JPN":"やはり変なお方。ほとんどの人は私に団長としての役割を要求していました。","ENG":"You really are unusual. Most people only ever demanded that I fulfill my duties as Captain.","TWN":"你果然是個奇妙的人呢，大部分的人都是看上我身為團長的職責與權力。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"그러지 않은 이들은, 기사단의 동료. 혹은…….","JPN":"そうでない者たちは騎士団の仲間か、あるいは……","ENG":"Those who didn't were fellow knights. Or...","TWN":"不會這樣的人通常是騎士團的夥伴，或者……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"죄송합니다. 제가 관리자님의 진심을 의심한 셈이 되어버렸군요.","JPN":"申し訳ありません。私が管理者の本気を疑ったような形となってしまいました。","ENG":"Forgive me. It seems I ended up questioning your sincerity.","TWN":"抱歉，我這樣說，似乎變成是在懷疑你的誠意。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"설령 계약을 앞세웠다고 한들 당신이 믿을 수 있는 사람이란 건 알고 있습니다.","JPN":"たとえ契約を先立てたとしても、あなたが信用できる人だということはわかっています。","ENG":"Even if this contract came first, I know you're someone I can trust.","TWN":"雖然是契約關係，但我知道你是值得信賴的人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"아직 조금 어색하지만…… ","JPN":"まだ少しぎこちないのですが……","ENG":"It still feels a little awkward, but...","TWN":"雖然還有些生疏……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"크흠. 알겠다.","JPN":"コホン。了解した。","ENG":"Ahem. Very well.","TWN":"咳咳，好的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"그대가 나와의 인연을 바란다면 나 역시 기사로서 합당한 각오를 마쳐야겠지.","JPN":"君が私との絆を望むのなら、私もまた騎士としてそれ相応の覚悟を決めるべきだろう。","ENG":"If you wish to forge a bond with me, then I too must stand ready, as a knight should.","TWN":"既然管理者希望與我立約，那我也該做出應有的回應才對。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"처녀자리의 기사. 에스테로사 드 슈발리에가 이곳에서 맹세하겠다.","JPN":"乙女座の騎士、エステロサ・ド・シュヴァリエがここで誓おう。","ENG":"I, Esterosa de Chevalier, Knight of Virgo, pledge my oath here and now.","TWN":"我處女座騎士，聖騎士艾斯特洛索發誓！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"이제부터 나의 검, 나의 모든 것은 오롯이 그대만을 위한 것.","JPN":"これから私の剣、私のすべては君のためだけのもの。","ENG":"From this moment on, my sword and my very being belongs solely to you.","TWN":"自此刻起，我的劍、我的一切，將專屬於管理者一人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"설령 어떤 위험이 도사리더라도 나는 그대를 밝히는 별빛이 되어 어둠을 밝히겠다.","JPN":"たとえどのような危険が待ち受けているとしても、私は君を照らす星の光となり、闇を追い払ってみせよう。","ENG":"No matter what dangers may lie ahead, I shall become your guiding starlight, shining through the darkness.","TWN":"就算前方有任何潛藏危險，我也將化為照亮你的星光，驅散所有黑暗。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"그러니 가능하다면… 그대라는 별 또한 나를 비춰줬으면 좋겠군.","JPN":"だから、できれば……君という星もまた、私を照らしてほしい。","ENG":"So if it's possible... I hope you'll be my star and shine upon me as well.","TWN":"所以…可以的話，也希望你這顆星星能為我帶來光芒。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NEXT_NULL","text":{"KOREA":"이래봬도, 제법 응석쟁이라서 말이야.","JPN":"こう見えても、結構甘えん坊だからな。","ENG":"I can be a bit clingy at times.","TWN":"別看我這樣，我也是很會撒嬌的人呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};